# 1. AMBIL SEMUA SISWA YANG SAAT INI TERDAFTAR DI DATABASE UNTUK GRUP INI
previous_links = frappe.db.get_all("Student Halaqah Link", 
    filters={"halaqah_group": doc.name, "parenttype": "Tahfizh Student"}, 
    fields=["parent"]
)
previous_students = set([p.parent for p in previous_links])

# 2. AMBIL DAFTAR SISWA YANG BARU/AKTIF DARI FORM SAAT INI
current_students = set()
if doc.get("table_tahfizh_student"):
    for row in doc.get("table_tahfizh_student"):
        # Ambil field student_id dari child table tabel siswa
        if row.get("student_id"):
            # Cari nama dokumen Tahfizh Student asli berdasarkan field student_id
            tahfizh_student_name = frappe.db.get_value("Tahfizh Student", {"student_id": row.student_id}, "name")
            if tahfizh_student_name:
                current_students.add(tahfizh_student_name)

# 3. BERSIHKAN SISWA YANG DIHAPUS DARI TABEL
students_to_remove = previous_students - current_students
for student_name in students_to_remove:
    if frappe.db.exists("Tahfizh Student", student_name):
        student_doc = frappe.get_doc("Tahfizh Student", student_name)
        
        updated_halaqah = [
            r for r in student_doc.get("halaqah_group") if r.halaqah_group != doc.name
        ]
        
        student_doc.set("halaqah_group", updated_halaqah)
        
        for index, r in enumerate(student_doc.get("halaqah_group"), start=1):
            r.idx = index
            
        student_doc.save(ignore_permissions=True)

# 4. TAMBAHKAN ATAU PERBARUI SISWA YANG AKTIF DI SINI
for student_name in current_students:
    if frappe.db.exists("Tahfizh Student", student_name):
        student_doc = frappe.get_doc("Tahfizh Student", student_name)
        
        existing_row = None
        for r in student_doc.get("halaqah_group"):
            if r.halaqah_group == doc.name:
                existing_row = r
                break
                
        if existing_row:
            existing_row.muhafizh = doc.muhafizh_name
        else:
            student_doc.append("halaqah_group", {
                "halaqah_group": doc.name,
                "muhafizh": doc.muhafizh_name
            })
            
        for index, r in enumerate(student_doc.get("halaqah_group"), start=1):
            r.idx = index
            
        student_doc.save(ignore_permissions=True)
